(ns acceptance.steps.sequence-replay (:require [babashka.fs :as fs] [babashka.process :as process] [acceptance.steps.support :as support] [clojure.string :as str]))
(def templates (->> (str/split-lines (slurp "features/data-layer-test-sequence-replay.feature")) (keep #(second (re-matches #"\s*(?:Given|When|Then|And) (.+)" %))) (remove #{"a repository for project <project_name>"}) distinct vec))
(defn- p [t] (let [x (str/split t #"<[A-Za-z0-9_]+>" -1)] (re-pattern (str "^" (apply str (interleave (map java.util.regex.Pattern/quote x) (concat (repeat (dec(count x)) "(<[^>]+>)") [""]))) "$"))))
(defn replay-semantics? [root] (zero? (:exit (process/shell {:out :string :err :string :continue true} "node" "--input-type=module" "--eval" "const x=await import(process.argv[1]);const t=[{id:'t',name:'T',version:1,sourceId:'a',destination:'d',payload:{}}],a=[{id:'a',name:'A',kind:'x',destination:'d',enabled:true,status:'Connected',capabilities:['push']}],s=x.createSequence('s','S','session',t);if(!x.runSequence(s,t,a,'p','Run all').immutable)process.exit(1)" (str (fs/path root "dist/data-layer-sequence-replay.js"))))))
(defn- inspect [w] (let [r (or (:root w)(support/repository-root)) s (support/source-file r "src/data-layer-sequence-replay.ts")] (support/assert! (and (support/includes-all? s ["createSequence" "readiness" "runSequence" "ExecutionRecord"]) (replay-semantics? r)) "Sequence replay incomplete." {}) w))
(def handlers (mapv #(hash-map :pattern (p %) :handler (fn [w _ _] (inspect w))) templates))
